"use client"
import * as React from "react"
import { cn } from "@/lib/utils"

interface MagneticButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  strength?: number
  glowColor?: string
}

export function MagneticButton({
  className, children,
  strength = 0.35,
  glowColor = "rgba(0,212,255,0.3)",
  ...props
}: MagneticButtonProps) {
  const ref = React.useRef<HTMLButtonElement>(null)
  const [offset, setOffset] = React.useState({ x: 0, y: 0 })
  const [hovered, setHovered] = React.useState(false)

  const onMove = (e: React.MouseEvent) => {
    const rect = ref.current!.getBoundingClientRect()
    setOffset({
      x: (e.clientX - rect.left - rect.width / 2) * strength,
      y: (e.clientY - rect.top - rect.height / 2) * strength,
    })
  }

  return (
    <button
      ref={ref}
      onMouseMove={onMove}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => { setOffset({ x: 0, y: 0 }); setHovered(false) }}
      className={cn(
        "relative rounded-full px-7 py-3 text-sm font-medium transition-all duration-150",
        className
      )}
      style={{
        transform: `translate(${offset.x}px, ${offset.y}px)`,
        border: `1px solid ${hovered ? "rgba(0,212,255,0.4)" : "rgba(255,255,255,0.1)"}`,
        background: hovered ? "rgba(0,212,255,0.08)" : "rgba(255,255,255,0.04)",
        color: hovered ? "#00d4ff" : "#888",
        boxShadow: hovered ? `0 0 30px ${glowColor}` : "none",
      }}
      {...props}
    >
      {children}
    </button>
  )
}
